mapper.select:
select i.sku, max(i.name) name, max(v.market) market, max(v.groupname) groupname, sum(i.quantity) as quantity, max(i.price) as price, sum(i.total_price) as total_price from t_erp_ship_v2_inboundshipment_customs_xml_item i left join t_erp_ship_v2_inboundshipment_customs_xml x on x.guid=i.guid left join ( select p.groupid, g.shopid, max(g.name) groupname, max(m.name) market,
i.ordguid guid,
i.invguid guid,
i.decguid guid,
i.decguid guid,
p.marketplaceid marketplaceid from t_erp_ship_v2_inboundshipment i left join t_erp_ship_v2_inboundplan p on p.id = i.formid left join t_erp_ship_inboundtrans t on t.shipmentid = i.shipment_confirmation_id left join t_amazon_group g on g.id = p.groupid left join t_marketplace m on m.marketplaceid = p.marketplaceid where p.shopid=#{dto.shopid}
and p.marketplaceid=#{dto.marketplaceid}
and p.groupid=#{dto.groupid}
group by p.groupid,p.marketplaceid,i.ordguid
group by p.groupid,p.marketplaceid,i.invguid
group by p.groupid,p.marketplaceid,i.decguid
group by p.groupid,p.marketplaceid,i.decguid
) v on v.guid=x.guid where v.shopid=#{dto.shopid}
and x.groupid=#{dto.groupid}
and x.xml_type=#{dto.xmlType}
and v.marketplaceid=#{dto.marketplaceid}
and x.app_time >=#{dto.fromDate,jdbcType=DATE} and x.app_time <=#{dto.toDate,jdbcType=DATE}
and x.opttime >=#{dto.fromDate,jdbcType=DATE} and x.opttime <=#{dto.toDate,jdbcType=DATE}
group by i.sku
